82	      SmallVector<std::tuple<unsigned, Value, Value>> replacements;
83	      BitVector replacedArgs(processedArgs.size());
84	      for (auto &op : *substMod) {
85	        auto subst = dyn_cast<cudaq::cc::ArgumentSubstitutionOp>(op);
86	        if (!subst) {
87	          if (auto symInterface = dyn_cast<SymbolOpInterface>(op)) {
88	            auto name = symInterface.getName();
89	            auto obj = moduleOp.lookupSymbol(name);
