#include <cudaq.h>
#include <cmath>

// 参数化子内核
__qpu__ void rot(double theta, cudaq::qubit &q) {
  ry(theta, q);
}

// 主内核
__qpu__ void chain(int n, std::vector<double> angles) {
  cudaq::qvector q(n);
  for (int i = 0; i < n; i++)
    rot(angles[i], q[i]);
  mz(q);
}

int main() {
  int n = 4;
  std::vector<double> angles = {0.0, M_PI/4, M_PI/2, 3.0*M_PI/4};
  auto counts = cudaq::sample(chain, n, angles);
  counts.dump();
}
```

